			if err := pFilter.Uninstall(); err != nil {
				logger.Errorf(err, "error Cleanup packetfilter table for IPv%v", family)
			}
		}

		return
	}

	defer http.StartServer(http.Profile, env.ProfilePort)()

	ctl, err := controller.New(&controller.Config{
		Registry:   registry,
		Client:     dynamicClientSet,
		RestMapper: restMapper,
	})
	logger.FatalOnError(err, "Error creating controller for event handling")

	stopCh := ctx.Done()

	err = ctl.Start(stopCh)
	logger.FatalOnError(err, "Error starting controller")

	cleanupLegacyIptables(env.ClusterCidr)

	<-stopCh
	ctl.Stop()

	logger.Info("All controllers stopped or exited. Stopping submariner-route-agent")
}

func init() {
	flag.StringVar(&kubeconfig, "kubeconfig", "", "Path to a kubeconfig. Only required if out-of-cluster.")
	flag.StringVar(&masterURL, "master", "",
		"The address of the Kubernetes API server. Overrides any value in kubeconfig. Only required if out-of-cluster.")
	flag.BoolVar(&showVersion, "version", showVersion, "Show version")
}

func getTCPMssValue(localNode *corev1.Node) int {
	tcpMssStr := localNode.GetAnnotations()[v1.TCPMssValue]

	if tcpMssStr == "" {
		return 0
	}

	tcpMssValue, err := strconv.Atoi(tcpMssStr)
	if err != nil {
		logger.Errorf(err, "Error parsing %q annotation", v1.TCPMssValue)
		return 0
	}

	return tcpMssValue
}

func uninstall(registry *event.Registry) {
	if err := registry.StopHandlers(context.TODO()); err != nil {
		logger.Warningf("Error stopping handlers: %v", err)
	}

	if err := registry.Uninstall(context.TODO()); err != nil {
		logger.Warningf("Error uninstalling handlers: %v", err)
	}
}

func removeInvalidSockets() {
	// This can be removed once we stop supporting upgrades from 0.16.0 or older
	for _, dir := range []string{"/run/openvswitch/db.sock", "/var/run/openvswitch/ovnnb_db.sock", "/var/run/ovn-ic/ovnnb_db.sock"} {
		info, err := os.Stat(dir)
		if (err == nil || errors.Is(err, fs.ErrExist)) && info.IsDir() {
			err := os.Remove(dir)
			if err != nil {
				logger.Errorf(err, "Failed to delete invalid socket %s", dir)
			} else {
				logger.Infof("Deleted invalid socket %s", dir)
			}
		}
	}
}

// =============================================================================
// TEMPORARY: iptables cleanup for migration to nftables
// This entire section can be removed once migration is complete
// =============================================================================

func cleanupLegacyIptables(clusterCidr []string) {
	if pfconfigure.GetDriverType() == pfconfigure.IPTables {
		return
	}

	ipHookChains := []struct {
		Table packetfilter.TableType
		Chain *packetfilter.ChainIPHook
	}{
		{
			Table: packetfilter.TableTypeNAT,
			Chain: chains.NewPostRouting(),
		},
		{
			Table: packetfilter.TableTypeFilter,
			Chain: chains.NewInput(),
		},
		{
			Table: packetfilter.TableTypeNAT,
			Chain: chains.NewSelfSnat(),
		},
		{
			Table: packetfilter.TableTypeFilter,
			Chain: chains.NewForwarding(),
		},
		{
			Table: packetfilter.TableTypeFilter,
			Chain: chains.NewForwardingMSSClamp(),
		},
		{
			Table: packetfilter.TableTypeRoute,
			Chain: &packetfilter.ChainIPHook{
				Name:     chains.SmPostRoutingMss,
				Type:     packetfilter.ChainTypeRoute,
				Hook:     packetfilter.ChainHookPostrouting,
				Priority: packetfilter.ChainPriorityFirst,
			},
		},
	}

	for _, family := range cidr.ExtractIPFamilies(clusterCidr) {
		pIPtables, err := iptables.New(family)
		if err != nil {
			logger.Errorf(err, "Failed to create IPv%v iptables driver for cleanup", family)
			continue
		}

		for _, item := range ipHookChains {
			_ = pIPtables.ClearChain(item.Table, item.Chain.Name)

			if err := pIPtables.DeleteIPHookChain(item.Chain); err != nil {
				logger.V(log.DEBUG).Infof("Failed to delete IPv%v iptables IP hook chain %q: %v", family, item.Chain.Name, err)
			} else {
				logger.Infof("Cleaned up IPv%v iptables IP hook chain %q", family, item.Chain.Name)
			}
		}
	}
}

