				g.Expect(ra.Status.RemoteEndpoints).To(HaveLen(1))
				g.Expect(ra.Status.RemoteEndpoints[0].Spec.GetHealthCheckIP(k8snet.IPv4)).To(Equal(healthCheckIP2))
			})
		})
