type contextCapturingHandler struct {
	event.HandlerBase
	stopCtx      context.Context
	uninstallCtx context.Context
	name         string
}

func (h *contextCapturingHandler) GetName() string {
	return h.name
}

func (h *contextCapturingHandler) GetNetworkPlugins() []string {
	return []string{event.AnyNetworkPlugin}
}

func (h *contextCapturingHandler) Stop(ctx context.Context) error {
	h.stopCtx = ctx
	return nil
